import pytest

from trezorlib import evolu
from trezorlib.debuglink import SessionDebugWrapper as Session

# make -C core test_emu TESTOPTS="-k test_sign_request.py"

pytestmark = pytest.mark.models("core")


def test_evolu_get_delegated_identity(session: "Session"):
    response = evolu.get_delegated_identity_key(session)
    private_key = response.private_key
    assert len(private_key) == 32

    response_2 = evolu.get_delegated_identity_key(session)
    assert response_2.private_key == private_key


def test_evolu_get_node(session: "Session"):
    proposed_value = bytes.fromhex(
        "1f77232aeff4d981134db23abf2aa2efa4fa647f1d300eab9dc6f733c6119a7fc73debae3642693aee8692c97e6ec7868b41c9469737c17fbde5d0bbc4354ef87a"
    )
    response = evolu.get_evolu_node(session, proof=proposed_value)

    check_value = bytes.fromhex(
        "a81aaf51997b6ddfa33d11c038d6aba5f711754a2c823823ff8b777825cdbb32b0e71c301fa381c75081bd3bcc134b63306aa6fc9a9f52d835ad4df8cd507be6"
    )
    assert response.data == check_value


def test_evolu_sign_request(session: "Session"):
    challenge = "1234"
    size = 10
    proposed_value = bytes.fromhex(
        "1f21c1e7f197f6b2102b0796868b24eb0eb5323f77a2c0c01044e523894b38f69920d93df1e3bef40e8dead4f0d01fe70c4172d14db044312cb4cd86e8c90ed77a"
    )
    response = evolu.evolu_sign_registration_request(
        session,
        challenge=bytes.fromhex(challenge),
        size=size,
        proof=proposed_value,
    )

    check_signature = bytes.fromhex(
        "3045022100a7f5fa73896edb323fc0b8f728f7becb89e2adcbab0b782d3cb837938790a92602207907a4d0309d9358d0315a01640b772ecd9955b01cb1a15099ef6c7d9325b39b"
    )
    check_certificates = [
        bytes.fromhex(
            ""
        ),
        bytes.fromhex(
            ""
        ),
    ]
    assert response.signature == check_signature
    assert response.certificates == check_certificates
